from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a natural‑language description from a list of triples."""
    if not triples:
        return ""

    # helper to strip surrounding quotes
    def clean(val: str) -> str:
        return val.strip('\"')

    # group triples by subject to avoid repeating the subject many times
    grouped: dict[str, list[Triple]] = {}
    for t in triples:
        grouped.setdefault(t.subject, []).append(t)

    sentences: list[str] = []

    for subj, group in grouped.items():
        # collect clause fragments for this subject
        clauses: list[str] = []
        for t in group:
            p, o = t.predicate, clean(t.object)

            if p == "birthDate":
                clauses.append(f"was born on {o}")
            elif p == "birthYear":
                clauses.append(f"was born in {o}")
            elif p == "birthPlace":
                clauses.append(f"was born in {o}")
            elif p == "deathDate":
                clauses.append(f"died on {o}")
            elif p == "deathPlace":
                clauses.append(f"died in {o}")
            elif p == "origin":
                clauses.append(f"originates from {o}")
            elif p == "genre":
                # Use a natural phrasing for genre
                clauses.append(f"is a {o.lower()} musician")
            elif p == "instrument":
                # Drop leading article if present and lower‑case instrument name
                instr = o.lower().replace("the ", "")
                clauses.append(f"plays {instr}")
            elif p == "occupation":
                clauses.append(f"is a {o.lower()}")
            elif p == "background":
                # background often describes type of artist
                clauses.append(f"is a {o.lower()}")
            elif p == "associatedBand/associatedMusicalArtist":
                # Prefer “member of” when the object looks like a band name
                if any(word.isupper() for word in o.split()):
                    clauses.append(f"is a member of {o}")
                else:
                    clauses.append(f"is associated with {o}")
            elif p == "recordLabel":
                clauses.append(f"is signed to {o}")
            elif p == "activeYearsStartYear":
                clauses.append(f"started {subj.split()[0]}'s career in {o}")
            elif p == "activeYearsEndYear":
                clauses.append(f"ended {subj.split()[0]}'s career in {o}")
            elif p == "nationality":
                clauses.append(f"is {o.lower()}")
            elif p == "capital":
                clauses.append(f"has capital {o}")
            elif p == "country":
                clauses.append(f"is from {o}")
            elif p == "isPartOf":
                clauses.append(f"is part of {o}")
            elif p in {"language", "officialLanguage"}:
                clauses.append(f"speaks {o}")
            elif p == "derivative":
                # Phrase derivative relations in a separate sentence later
                clauses.append(f"is a derivative of {o}")
            elif p == "stylisticOrigin":
                clauses.append(f"originated from {o}")
            elif p == "musicFusionGenre":
                clauses.append(f"is a fusion of {subj.lower()} and {o.lower()}")
            elif p == "musicSubgenre":
                clauses.append(f"is a subgenre of {subj.lower()}, namely {o.lower()}")
            elif p == "derivative":
                clauses.append(f"is a derivative of {subj.lower()}")
            elif p == "stylisticOrigin":
                clauses.append(f"has stylistic origin in {o.lower()}")
            else:
                clauses.append(f"{p} {o}")

        # Build the sentence for this subject
        if not clauses:
            continue
        if len(clauses) == 1:
            sentence = f"{subj} {clauses[0]}."
        else:
            # join with commas and an "and" before the last clause
            sentence = f"{subj} " + ", ".join(clauses[:-1]) + ", and " + clauses[-1] + "."
        sentences.append(sentence)

    # Combine sentences for different subjects into one paragraph
    return " ".join(sentences)

